import { useState } from 'react';
import { useDispatch } from 'store';

// material-ui
import Button from '@mui/material/Button';
import CardContent from '@mui/material/CardContent';
import Grid from '@mui/material/Grid';
import IconButton from '@mui/material/IconButton';
import InputAdornment from '@mui/material/InputAdornment';
import TextField from '@mui/material/TextField';
import Tooltip from '@mui/material/Tooltip';

// third party
import copy from 'copy-to-clipboard';

// project imports
import MainCard from 'ui-component/cards/MainCard';
import SecondaryAction from 'ui-component/cards/CardSecondaryAction';
import SubCard from 'ui-component/cards/SubCard';
import { openSnackbar } from 'store/slices/snackbar';
import { gridSpacing } from 'store/constant';

// assets
import ContentCopyTwoToneIcon from '@mui/icons-material/ContentCopyTwoTone';
import ContentCutTwoToneIcon from '@mui/icons-material/ContentCutTwoTone';
import LinkIcon from '@mui/icons-material/Link';

// ==============================|| PLUGIN - COPY TO CLIPBOARD ||============================== //

export default function ClipboardPage() {
  const dispatch = useDispatch();

  const [text1, setText1] = useState('https://berrydashboard.com/');
  const [text2, setText2] = useState(
    'Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.'
  );
  const [text3] = useState(
    'Lorem ipsum cacilds, vidis litro abertis. Consetis adipiscings elitis. Pra lá , depois divoltis porris, paradis. Paisis, filhis, espiritis santis. Mé faiz elementum girarzis, nisi eros vermeio, in elementis mé pra quem é amistosis quis leo. Manduma pindureta quium dia nois paga.'
  );

  const handleCopy = (text, successMessage) => {
    copy(text);
    dispatch(
      openSnackbar({
        open: true,
        message: successMessage,
        variant: 'alert',
        alert: { color: 'success' },
        close: false,
        anchorOrigin: { vertical: 'top', horizontal: 'right' },
        transition: 'SlideLeft'
      })
    );
  };

  return (
    <MainCard
      title="Clipboard"
      secondary={
        <SecondaryAction icon={<LinkIcon sx={{ fontSize: 'small' }} />} link="https://www.npmjs.com/package/react-copy-to-clipboard" />
      }
    >
      <Grid container spacing={gridSpacing}>
        <Grid size={12}>
          <SubCard title="Copy from TextField">
            <TextField
              fullWidth
              label="Website"
              type="text"
              value={text1}
              onChange={(e) => {
                setText1(e.target.value);
              }}
              slotProps={{
                input: {
                  endAdornment: (
                    <InputAdornment position="end">
                      <Tooltip title="Copy">
                        <IconButton
                          aria-label="Copy from another element"
                          edge="end"
                          size="large"
                          onClick={() => handleCopy(text1, 'Text Copied')}
                        >
                          <ContentCopyTwoToneIcon sx={{ fontSize: '1.1rem' }} />
                        </IconButton>
                      </Tooltip>
                    </InputAdornment>
                  )
                }
              }}
            />
          </SubCard>
        </Grid>
        <Grid size={{ xs: 12, md: 6 }}>
          <SubCard title="Copy from TextArea">
            <TextField
              multiline
              rows={4}
              fullWidth
              label="Copy text"
              onChange={(e) => setText2(e.target.value)}
              value={text2}
              sx={{ mb: gridSpacing }}
            />
            <Button variant="contained" size="small" sx={{ mr: 1.5 }} onClick={() => handleCopy(text2, 'Text Copied')}>
              <ContentCopyTwoToneIcon sx={{ fontSize: '1rem', mr: 1 }} /> Copy
            </Button>
            <Button
              variant="contained"
              size="small"
              color="secondary"
              onClick={() => {
                setText2('');
                handleCopy(text2, 'Text Cut');
              }}
            >
              <ContentCutTwoToneIcon sx={{ fontSize: '1rem', mr: 1 }} /> Cut
            </Button>
          </SubCard>
        </Grid>
        <Grid size={{ xs: 12, md: 6 }}>
          <SubCard
            title="Copy from Container"
            secondary={
              <Tooltip title="Copy">
                <Button variant="contained" sx={{ mr: 1.5, px: 1, minWidth: 'auto' }} onClick={() => handleCopy(text3, 'Text Copied')}>
                  <ContentCopyTwoToneIcon sx={{ fontSize: '1rem' }} />
                </Button>
              </Tooltip>
            }
          >
            <CardContent sx={{ p: 0, pb: 2.5 }}>{text3}</CardContent>
          </SubCard>
        </Grid>
      </Grid>
    </MainCard>
  );
}
